#include <iostream>
#include <string>
#include <memory>
#include <map>
#include <functional>
#include <set>
#include <algorithm>
#include <stdexcept>

class Notification {
public:
    virtual ~Notification() = default;
    virtual void send(const std::string& message) = 0;
    virtual std::string getType() const = 0;
};

class EmailNotification : public Notification {
public:
    void send(const std::string& message) override {
        std::cout << "[EMAIL] " << message << std::endl;
    }
    std::string getType() const override { return "email"; }
};

class SMSNotification : public Notification {
public:
    void send(const std::string& message) override {
        std::cout << "[SMS] " << message << std::endl;
    }
    std::string getType() const override { return "sms"; }
};

class PushNotification : public Notification {
public:
    void send(const std::string& message) override {
        std::cout << "[PUSH] " << message << std::endl;
    }
    std::string getType() const override { return "push"; }
};

using Creator = std::function<std::unique_ptr<Notification>()>;

class NotificationFactory {
    static std::map<std::string, Creator>& getRegistry() {
        static std::map<std::string, Creator> registry;
        return registry;
    }

    static std::string toLower(std::string s) {
        std::transform(s.begin(), s.end(), s.begin(), ::tolower);
        return s;
    }

public:
    static void registerType(const std::string& type, Creator creator) {
        getRegistry()[toLower(type)] = std::move(creator);
    }

    static std::unique_ptr<Notification> create(const std::string& type) {
        auto& reg = getRegistry();
        auto it = reg.find(toLower(type));
        if (it == reg.end()) {
            throw std::invalid_argument("Unknown type: " + type);
        }
        return it->second();
    }

    static void printRegisteredTypes() {
        std::cout << "Registered: [";
        bool first = true;
        for (auto& [key, _] : getRegistry()) {
            if (!first) std::cout << ", ";
            std::cout << key;
            first = false;
        }
        std::cout << "]" << std::endl;
    }
};

// Self-registration — types register themselves
struct AutoRegister {
    AutoRegister() {
        NotificationFactory::registerType("email",
            []() { return std::make_unique<EmailNotification>(); });
        NotificationFactory::registerType("sms",
            []() { return std::make_unique<SMSNotification>(); });
        NotificationFactory::registerType("push",
            []() { return std::make_unique<PushNotification>(); });
    }
} autoReg;

int main() {
    // Test existing types
    NotificationFactory::create("email")->send("Welcome!");
    NotificationFactory::create("sms")->send("OTP: 1234");
    NotificationFactory::create("push")->send("New message");

    NotificationFactory::printRegisteredTypes();

    // RUNTIME registration — no Factory code changes!
    NotificationFactory::registerType("whatsapp", []() {
        class WhatsApp : public Notification {
        public:
            void send(const std::string& msg) override {
                std::cout << "[WHATSAPP] " << msg << std::endl;
            }
            std::string getType() const override { return "whatsapp"; }
        };
        return std::make_unique<WhatsApp>();
    });

    NotificationFactory::create("whatsapp")->send("Runtime registration works!");
    NotificationFactory::printRegisteredTypes();

    std::cout << "REGISTRY TESTS PASSED" << std::endl;
    return 0;
}

