    virtual std::string generate(const std::vector<std::string>& items,
                                  double total, double tax) = 0;
};

// Helper to format doubles
std::string fmt(double val) {
    std::ostringstream ss;
    ss << std::fixed << std::setprecision(2) << val;
    return ss.str();
}

std::string joinItems(const std::vector<std::string>& items) {
    std::string result = "[";
    for (size_t i = 0; i < items.size(); i++) {
        if (i > 0) result += ", ";
        result += items[i];
    }
    return result + "]";
}

// India family
class GSTCalculator : public TaxCalculator {
public:
    double calculate(double amount) override { return amount * 0.18; }
    std::string getDescription() override { return "GST 18%"; }
};

class RupeeFormatter : public CurrencyFormatter {
public:
    std::string format(double amount) override {
        return "Rs. " + fmt(amount);
    }
};

class IndiaReceiptGenerator : public ReceiptGenerator {
public:
    std::string generate(const std::vector<std::string>& items,
                          double total, double tax) override {
        return "=== INDIAN TAX INVOICE ===\n"
            "Items: " + joinItems(items) + "\n"
            "Subtotal: Rs. " + fmt(total) + "\n"
            "GST (18%): Rs. " + fmt(tax) + "\n"
            "Total: Rs. " + fmt(total + tax) + "\n"
            "GSTIN: 27AABCU9603R1ZJ";
    }
