        return "$" + fmt(amount);
    }
};

class USReceiptGenerator : public ReceiptGenerator {
public:
    std::string generate(const std::vector<std::string>& items,
                          double total, double tax) override {
        return "=== US RECEIPT ===\n"
            "Items: " + joinItems(items) + "\n"
            "Subtotal: $" + fmt(total) + "\n"
            "Tax (8.25%): $" + fmt(tax) + "\n"
